UPDATE curso SET
  descricao = 'O curso de Análise e Desenvolvimento de Sistemas forma profissionais capacitados para desenvolver, implementar e manter sistemas de software de alto desempenho. Com uma grade curricular atualizada e metodologias ágeis, o egresso estará apto a atuar com linguagens modernas (Java, Python, JavaScript), bancos de dados relacionais e NoSQL, arquiteturas de microserviços e cloud computing. O curso alia teoria à prática intensa por meio de laboratórios, projetos interdisciplinares e parceria com empresas da região.',
