WHERE codigo = 'TADS';

UPDATE curso SET
  descricao = 'O curso de Gestão Empresarial prepara líderes e empreendedores para os desafios do mercado contemporâneo. Os alunos desenvolvem competências em planejamento estratégico, gestão financeira, marketing digital, recursos humanos e empreendedorismo. Com um olhar voltado para a inovação e sustentabilidade, o egresso está habilitado a gerir departamentos, criar novos negócios e transformar organizações públicas e privadas.',
