-- -------------------------------------------------------
-- DISCIPLINAS — ementas mais detalhadas
-- -------------------------------------------------------
UPDATE disciplina SET ementa = 'Introdução à lógica de programação e pensamento computacional. Algoritmos e fluxogramas. Variáveis, tipos de dados e operadores. Estruturas de controle: condicionais e laços. Sub-rotinas e funções. Introdução à linguagem Python e/ou Java. Vetores e matrizes. Resolução de problemas práticos com código.' WHERE codigo = 'ALG001';

UPDATE disciplina SET ementa = 'Fundamentos de banco de dados relacional. Modelo Entidade-Relacionamento (ER). Projeto conceitual, lógico e físico. Normalização e formas normais. SQL completo: DDL, DML, DQL. Funções de agregação, JOINs, subconsultas. Introdução ao PostgreSQL e MySQL. Boas práticas de modelagem.' WHERE codigo = 'BD001';

UPDATE disciplina SET ementa = 'Introdução à Engenharia de Software. Modelos de ciclo de vida: cascata, espiral e ágil. Scrum e Kanban na prática. Levantamento e gestão de requisitos. Modelagem UML: casos de uso, diagrama de classes, sequência e atividades. Qualidade de software e testes. Gestão de configuração e versionamento com Git.' WHERE codigo = 'ES001';

UPDATE disciplina SET ementa = 'Fundamentos da Programação Orientada a Objetos com Java. Classes, objetos, atributos e métodos. Encapsulamento, herança e polimorfismo. Interfaces e classes abstratas. Tratamento de exceções. Collections Framework. Generics e lambdas. Padrões de projeto (Design Patterns) introdutórios.' WHERE codigo = 'POO001';

UPDATE disciplina SET ementa = 'Estrutura de documentos HTML5 semântico. Estilização com CSS3: Flexbox e Grid Layout. Responsividade e mobile first. JavaScript moderno (ES6+): variáveis, funções, assincronismo, fetch API. Introdução ao React: componentes, props, estado e hooks. Ferramentas de build: Vite e Webpack.' WHERE codigo = 'WEB001';

UPDATE disciplina SET ementa = 'Criação de APIs RESTful com Node.js e Express. Autenticação com JWT. Integração com banco de dados via ORM (Sequelize/Prisma). Tratamento de erros e validação de dados. Testes de API com Postman e Jest. Deploy em provedores cloud: Railway, Render e AWS. Introdução a microserviços.' WHERE codigo = 'WEB002';

UPDATE disciplina SET ementa = 'Listas encadeadas simples e duplas. Pilhas e filas. Árvores binárias de busca e AVL. Tabelas hash. Grafos: representações e algoritmos (BFS, DFS, Dijkstra). Complexidade de algoritmos (notação Big-O). Algoritmos de ordenação e busca. Implementações práticas em Java ou Python.' WHERE codigo = 'ED001';

UPDATE disciplina SET ementa = 'Bancos de dados NoSQL: conceitos, categorias e casos de uso. MongoDB na prática: CRUD, aggregation pipeline, índices. Redis como cache e message broker. Transações e controle de concorrência em bancos relacionais. Query optimization e explain plans. Replicação e particionamento (sharding).' WHERE codigo = 'BD002';

UPDATE disciplina SET ementa = 'Conceitos de gerenciamento de projetos de software. PMBOK e metodologias ágeis. Planejamento: escopo, tempo, custo e riscos. Ferramentas: Jira, Trello e GitHub Projects. Estimativas de esforço (Planning Poker, Story Points). Monitoramento e controle de projetos. Gestão de equipes e comunicação.' WHERE codigo = 'GP001';

UPDATE disciplina SET ementa = 'Conceitos de segurança da informação: confidencialidade, integridade e disponibilidade. Criptografia simétrica e assimétrica. HTTPS e certificados TLS/SSL. Autenticação multifator e OAuth 2.0. OWASP Top 10: principais vulnerabilidades web. Firewall, IDS e IPS. LGPD e privacidade de dados. Pentest introdutório.' WHERE codigo = 'SEG001';

